  class RegisterPharmacyUI {
    +newPharmacy(managerName,email,password,nif,name,latitude,longitude,streetName,doorNumber,postalCode,locality,country)
    +registerPharmacy()
  }
}

package "Data" <<Data>> {
  class DataHandler {
    +openConnection()
    +closeAll()
  }
  class PharmacyDB {
    +PharmacyDB()
    +registerPharmacy()
  }
}

package "Controller" <<Controller>> {
  class RegisterPharmacyController {
    +newPharmacy(managerName,email,password,nif,name,latitude,longitude,streetName,doorNumber,postalCode,locality,country)
    +registerPharmacy()
  }
}

package "Model" <<Model>> {
  package "Service" <<Service>> {
    class PharmacyService {
      +PharmacyService()
      +addPharmacy(name,pharmacyManager,latitude,longitude,streetName,doorNumber,postalCode,locality,country)
      +registerPharmacy()
    }
  }
  class Pharmacy {
    -int id
    -String name
    -String email
  }
  class Address {
    -String streetName
    -String doorNumber
    -String postalCode
    -String locality
    -String country
    -float longitude
    -float latitude
  }
  class ScooterPark {
    -int maxSlotsNumber
